{"id":"/subscriptions/46270230-d55e-4d1a-b572-87635ce7a440/resourceGroups/rg-merlino/providers/Microsoft.OperationalInsights/workspaces/sentinel-merlino-workspace/providers/Microsoft.SecurityInsights/alertRules/2617fbe1-94a2-42cb-b11d-8a5be895c3c3","name":"2617fbe1-94a2-42cb-b11d-8a5be895c3c3","etag":""fd027a21-0000-1100-0000-68eaa8c90000"","type":"Microsoft.SecurityInsights/alertRules","kind":"Scheduled","properties":{"queryFrequency":"PT1H","queryPeriod":"PT1H","triggerOperator":"GreaterThan","triggerThreshold":0,"eventGroupingSettings":{"aggregationKind":"SingleAlert"},"incidentConfiguration":{"createIncident":true,"groupingConfiguration":{"enabled":false,"reopenClosedIncident":false,"lookbackDuration":"PT5H","matchingMethod":"AllEntities","groupByEntities":[],"groupByAlertDetails":[],"groupByCustomDetails":[]}},"entityMappings":[{"entityType":"Host","fieldMappings":[{"identifier":"FullName","columnName":"DeviceName"},{"identifier":"HostName","columnName":"HostName"},{"identifier":"DnsDomain","columnName":"DnsDomain"}]},{"entityType":"Process","fieldMappings":[{"identifier":"ProcessId","columnName":"ProcessId"},{"identifier":"CommandLine","columnName":"ProcessCommandLine"}]}],"templateVersion":"1.0.0","severity":"Medium","query":"DeviceProcessEvents
// Pro-tip: 
// There are many different ways to run a process from a file - e.g. by using full path, env. variables, ~1 annotation, more...
// So, to find executions of a known filename, better filter on the filename (and possibly on folder path) than on the commandline.
| where FileName in~ ("net.exe", "net1.exe")
// Parse the user name from the commandline.
// To have case-insensitive parsing use the i flag, to have non-greedy match (e.g. CreatedUser as short as possible), specify U flag:
// "kind=regex flags=i"
| parse kind=regex flags=iU ProcessCommandLine with * "user " CreatedUser " " * "/ad"
// Filter rows where user could not be parsed - e.g. because it was not a user command, or the /add commandline switch was not specified.
| where isnotempty(CreatedUser)
// Every net.exe executed will run net1.exe with the same commandline.
// in this where clause we remove such rows, as they duplicate the number of results we have without adding any value.
| where not (FileName =~ "net1.exe" and InitiatingProcessFileName =~ "net.exe" and replace("net", "net1", InitiatingProcessCommandLine) =~ ProcessCommandLine)
// If /domain is specified, so the user is created on the domain controller.
// Also, any prefix that's longer than 1 char will also do the same, e.g. /do, /dom, /doma, ....
| extend CreatedOnLocalMachine=(ProcessCommandLine !contains "/do")
| where ProcessCommandLine !contains "/add" or (CreatedOnLocalMachine == 0 and ProcessCommandLine !contains "/domain")
| summarize MachineCount=dcount(DeviceName) by CreatedUser, CreatedOnLocalMachine, InitiatingProcessFileName, FileName, ProcessId, ProcessCommandLine, InitiatingProcessCommandLine, DeviceId, DeviceName
| extend HostName = iff(DeviceName has '.', substring(DeviceName, 0, indexof(DeviceName, '.')), DeviceName)
| extend DnsDomain = iff(DeviceName has '.', substring(DeviceName, indexof(DeviceName, '.') + 1), "")
","suppressionDuration":"PT1H","suppressionEnabled":false,"tactics":["Persistence"],"techniques":["T1136"],"displayName":"Account Creation","enabled":true,"description":"User accounts may be created to achieve persistence on a machine.
Read more here: https://attack.mitre.org/wiki/Technique/T1136.
Tags: #CreateAccount.
Query #1: Query for users being created using "net user" command.
"net user" commands are noisy, so needs to be joined with another signal -.
E.g. in this example we look for use of uncommon & undocumented commandline switches (e.g. /ad instead of /add).","alertRuleTemplateName":"450f4e56-5bba-4070-b9d9-9204ba9d777d","lastModifiedUtc":"2025-10-11T18:58:16.2525413Z"}}

{"id":"/subscriptions/46270230-d55e-4d1a-b572-87635ce7a440/resourceGroups/rg-merlino/providers/Microsoft.OperationalInsights/workspaces/sentinel-merlino-workspace/providers/Microsoft.SecurityInsights/alertRules/2c9fddac-e3a5-4cbc-9668-1aefce7c7dcc","name":"2c9fddac-e3a5-4cbc-9668-1aefce7c7dcc","etag":""fd028b25-0000-1100-0000-68eaa8ef0000"","type":"Microsoft.SecurityInsights/alertRules","kind":"Scheduled","properties":{"queryFrequency":"PT1H","queryPeriod":"P7D","triggerOperator":"GreaterThan","triggerThreshold":0,"eventGroupingSettings":{"aggregationKind":"SingleAlert"},"incidentConfiguration":{"createIncident":true,"groupingConfiguration":{"enabled":false,"reopenClosedIncident":false,"lookbackDuration":"PT5H","matchingMethod":"AllEntities","groupByEntities":[],"groupByAlertDetails":[],"groupByCustomDetails":[]}},"entityMappings":[{"entityType":"Host","fieldMappings":[{"identifier":"FullName","columnName":"Computer"},{"identifier":"HostName","columnName":"HostName"},{"identifier":"DnsDomain","columnName":"HostNameDomain"}]},{"entityType":"IP","fieldMappings":[{"identifier":"Address","columnName":"AttackerIP"}]}],"templateVersion":"1.0.4","severity":"Medium","query":"let alertTimeWindow = 1h;
let logTimeWindow = 7d;
// Define script extensions that suit your web application environment - a sample are provided below
let scriptExtensions = dynamic([".php", ".jsp", ".js", ".aspx", ".asmx", ".asax", ".cfm", ".shtml"]);
let alertData = materialize(SecurityAlert
| where TimeGenerated > ago(alertTimeWindow)
| where ProviderName == "MDATP"
// Parse and expand the alert JSON
| extend alertData = parse_json(Entities)
| mvexpand alertData);
let fileData = alertData
// Extract web script files from MDATP alerts - our malicious web scripts - candidate webshells
| where alertData.Type =~ "file"
| where alertData.Name has_any(scriptExtensions)
| extend FileName = tostring(alertData.Name), Directory = tostring(alertData.Directory);
let hostData = alertData
// Extract server details from alerts and map to alert id
| where alertData.Type =~ "host"
| project HostName = tostring(alertData.HostName), DnsDomain = tostring(alertData.DnsDomain), SystemAlertId
| distinct HostName, DnsDomain, SystemAlertId;
// Join the files on their impacted servers
let webshellData = fileData
| join kind=inner (hostData) on SystemAlertId
| project TimeGenerated, FileName, Directory, HostName, DnsDomain;
webshellData
| join (
// Find requests that were made to this file on the impacted server in the W3CIISLog table
W3CIISLog
| where TimeGenerated > ago(logTimeWindow)
// Restrict to accesses to script extensions
| where csUriStem has_any(scriptExtensions)
| extend splitUriStem = split(csUriStem, "/")
| extend FileName = splitUriStem[-1], HostName = sComputerName
// Summarize potential attacker activity
| summarize count(), StartTime=min(TimeGenerated), EndTime=max(TimeGenerated), RequestUserAgents=make_set(csUserAgent), ReqestMethods=make_set(csMethod), RequestStatusCodes=make_set(scStatus), RequestCookies=make_set(csCookie), RequestReferers=make_set(csReferer), RequestQueryStrings=make_set(csUriQuery) by AttackerIP=cIP, SiteName=sSiteName, ShellLocation=csUriStem, tostring(FileName), HostName
) on FileName, HostName
| project StartTime, EndTime, AttackerIP, RequestUserAgents, Computer = HostName, SiteName, ShellLocation, ReqestMethods, RequestStatusCodes, RequestCookies, RequestReferers, RequestQueryStrings, RequestCount = count_
| extend HostName = tostring(split(Computer, ".")[0]), DomainIndex = toint(indexof(Computer, '.'))
| extend HostNameDomain = iff(DomainIndex != -1, substring(Computer, DomainIndex + 1), Computer)
","suppressionDuration":"PT1H","suppressionEnabled":false,"tactics":["Persistence"],"techniques":["T1505"],"displayName":"Malicious web application requests linked with Microsoft Defender for Endpoint (formerly Microsoft Defender ATP) alerts","enabled":true,"description":"Takes Microsoft Defender for Endpoint (formerly Microsoft Defender ATP) alerts where web scripts are present in the evidence and correlates with requests made to those scripts in the WCSIISLog to surface new alerts for potentially malicious web request activity.
The lookback for alerts is set to 1h and the lookback for W3CIISLogs is set to 7d. A sample set of popular web script extensions has been provided in scriptExtensions that should be tailored to your environment.","alertRuleTemplateName":"fbfbf530-506b-49a4-81ad-4030885a195c","lastModifiedUtc":"2025-10-11T18:58:54.5115929Z"}}

{"id":"/subscriptions/46270230-d55e-4d1a-b572-87635ce7a440/resourceGroups/rg-merlino/providers/Microsoft.OperationalInsights/workspaces/sentinel-merlino-workspace/providers/Microsoft.SecurityInsights/alertRules/4df819e6-cc6e-4d6a-9341-e413e93be10e","name":"4df819e6-cc6e-4d6a-9341-e413e93be10e","etag":""fd02f429-0000-1100-0000-68eaa91a0000"","type":"Microsoft.SecurityInsights/alertRules","kind":"Scheduled","properties":{"queryFrequency":"PT2H","queryPeriod":"PT2H","triggerOperator":"GreaterThan","triggerThreshold":0,"eventGroupingSettings":{"aggregationKind":"SingleAlert"},"incidentConfiguration":{"createIncident":true,"groupingConfiguration":{"enabled":false,"reopenClosedIncident":false,"lookbackDuration":"PT5H","matchingMethod":"AllEntities","groupByEntities":[],"groupByAlertDetails":[],"groupByCustomDetails":[]}},"entityMappings":[{"entityType":"Account","fieldMappings":[{"identifier":"FullName","columnName":"Account"},{"identifier":"Name","columnName":"Name"},{"identifier":"NTDomain","columnName":"NTDomain"}]},{"entityType":"Host","fieldMappings":[{"identifier":"FullName","columnName":"Computer"},{"identifier":"HostName","columnName":"HostName"},{"identifier":"DnsDomain","columnName":"DnsDomain"}]},{"entityType":"IP","fieldMappings":[{"identifier":"Address","columnName":"IpAddress"}]}],"templateVersion":"1.0.7","severity":"Low","query":"let timeRange = 2h;
let authenticationWindow = 1h;
let authenticationThreshold = 5;
SecurityEvent
| where TimeGenerated > ago(timeRange)
| where EventID in (4624, 4625)
| where IpAddress != "-" and isnotempty(Account)
| extend Outcome = iff(EventID == 4624, "Success", "Failure")
// bin outcomes into 10 minute windows to reduce the volume of data
| summarize OutcomeCount=count() by bin(TimeGenerated, 10m), Account, IpAddress, Computer, Outcome
| project TimeGenerated, Account, IpAddress, Computer, Outcome, OutcomeCount
// sort ready for sessionizing - by account and time of the authentication outcome
| sort by TimeGenerated asc, Account, IpAddress, Computer, Outcome, OutcomeCount
| serialize
// sessionize into failure groupings until either the account changes or there is a success
| extend SessionStartedUtc = row_window_session(TimeGenerated, timeRange, authenticationWindow, Account != prev(Account) or prev(Outcome) == "Success")
// count the failures in each session
| summarize FailureCountBeforeSuccess=sumif(OutcomeCount, Outcome == "Failure"), StartTime=min(TimeGenerated), EndTime=max(TimeGenerated), make_list(Outcome, 128), make_set(Computer, 128), make_set(IpAddress, 128) by SessionStartedUtc, Account
// the session must not start with a success, and must end with one
| where array_index_of(list_Outcome, "Success") != 0
| where array_index_of(list_Outcome, "Success") == array_length(list_Outcome) - 1
| project-away SessionStartedUtc, list_Outcome
// where the number of failures before the success is above the threshold
| where FailureCountBeforeSuccess >= authenticationThreshold
// expand out ip and computer for customer entity assignment
| mv-expand set_IpAddress, set_Computer
| extend IpAddress = tostring(set_IpAddress), Computer = tostring(set_Computer)
| extend timestamp=StartTime, NTDomain = split(Account, '\\', 0)[0], Name = split(Account, '\\', 1)[0], HostName = tostring(split(Computer, '.', 0)[0]), DnsDomain = tostring(strcat_array(array_slice(split(Computer, '.'), 1, -1), '.'))
","suppressionDuration":"PT1H","suppressionEnabled":false,"tactics":["CredentialAccess"],"techniques":["T1110"],"displayName":"SecurityEvent - Multiple authentication failures followed by a success","enabled":true,"description":"Identifies accounts who have failed to logon to the domain multiple times in a row, followed by a successful authentication within a short time frame. Multiple failed attempts followed by a success can be an indication of a brute force attempt or possible mis-configuration of a service account within an environment.
The lookback is set to 2h and the authentication window and threshold are set to 1h and 5, meaning we need to see a minimum of 5 failures followed by a success for an account within 1 hour to surface an alert.","alertRuleTemplateName":"cf3ede88-a429-493b-9108-3e46d3c741f7","lastModifiedUtc":"2025-10-11T18:59:38.0578639Z"}}
